'use client';

import { useAuth } from '@/context/AuthContext';
import { useRouter } from 'next/navigation';
import { useEffect, useState } from 'react';
import Navbar from '@/components/layout/Navbar';
import { Users, BookOpen, Star, PlusCircle } from 'lucide-react';

export default function ComunidadPage() {
  const { user, loading } = useAuth();
  const router = useRouter();
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!loading && !user && mounted) {
      router.push('/login');
    }
  }, [user, loading, router, mounted]);

  if (loading || !mounted || !user) {
    return (
      <div className="min-h-screen flex items-center justify-center">
        <div className="w-16 h-16 border-4 border-primary-200 border-t-primary-600 rounded-full animate-spin"></div>
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-black/5 dark:bg-white/5">
      <Navbar />

      <div className="pt-32 pb-20 max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <header className="mb-12">
          <div className="inline-flex items-center gap-2 px-3 py-1 bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400 rounded-full text-xs font-bold uppercase tracking-wider mb-4">
            <Star className="w-4 h-4" />
            Acceso VIP Activo
          </div>
          <h1 className="text-4xl lg:text-5xl font-display font-bold mb-4">
            Comunidad Raíces
          </h1>
          <p className="text-lg text-foreground/70 max-w-2xl">
            Bienvenido al espacio exclusivo para miembros de Vivero Libertad. 
            Comparte tus avances, aprende de expertos y conecta con otros amantes de la naturaleza.
          </p>
        </header>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
          <div className="col-span-1 md:col-span-2 space-y-6">
            {/* Feed Section (Placeholder) */}
            <div className="glass shadow-sm dark:glass-dark rounded-3xl p-6 border border-black/5 dark:border-white/5">
              <div className="flex items-center gap-4 border-b border-black/5 dark:border-white/5 pb-6 mb-6">
                <div className="w-12 h-12 rounded-full bg-primary-100 flex items-center justify-center text-primary-700 font-bold text-lg">
                  {user.email?.charAt(0).toUpperCase()}
                </div>
                <button className="flex-1 text-left px-4 py-3 rounded-full bg-black/5 dark:bg-white/5 text-foreground/50 hover:bg-black/10 transition-colors">
                  ¿Cómo va creciendo tu jardín hoy?
                </button>
              </div>

              <div className="space-y-6">
                <div className="p-4 rounded-2xl bg-black/5 dark:bg-white/5 opacity-50 text-center">
                  El foro de discusiones estará disponible muy pronto...
                </div>
              </div>
            </div>
          </div>

          <div className="space-y-6">
            {/* Sidebar */}
            <button className="w-full flex items-center justify-center gap-2 py-4 rounded-2xl bg-primary-600 hover:bg-primary-700 text-white font-medium transition-all shadow-lg shadow-primary-500/20">
              <PlusCircle className="w-5 h-5" />
              Nueva Publicación
            </button>

            <div className="glass shadow-sm dark:glass-dark rounded-3xl p-6 border border-black/5 dark:border-white/5">
              <h3 className="font-display font-bold text-lg mb-4 flex items-center gap-2">
                <BookOpen className="w-5 h-5 text-primary-500" />
                Guías Exclusivas
              </h3>
              <ul className="space-y-3 text-sm">
                <li><a href="#" className="text-foreground/70 hover:text-primary-600 transition-colors">🌿 Cómo propagar la Monstera</a></li>
                <li><a href="#" className="text-foreground/70 hover:text-primary-600 transition-colors">💧 Guía definitiva de riego en invierno</a></li>
